46. // NewSpinner creates a new Spinner instance.
47. func NewSpinner(options *SpinnerOptions) *Spinner {
48. 	mergedConfig := SpinnerOptions{}
49. 	if err := mergo.Merge(&mergedConfig, options); err != nil {
50. 		panic(err)
51. 	}
52. 
53. 	if err := mergo.Merge(&mergedConfig, DefaultSpinnerOptions); err != nil {
54. 		panic(err)
55. 	}
56. 
57. 	return &Spinner{
58. 		options: &mergedConfig,
59. 		text:    mergedConfig.Text,
60. 		cursor:  internal.NewCursor(mergedConfig.Writer),
61. 	}
62. }
