73. // Start starts the spinner.
74. func (s *Spinner) Start(ctx context.Context) error {
75. 	if s.canvas == nil {
76. 		s.canvas = NewCanvas(s).WithWriter(s.options.Writer)
77. 	}
78. 
79. 	s.clear = false
80. 	s.cursor.HideCursor()
81. 
82. 	if err := s.canvas.Run(); err != nil {
83. 		return err
84. 	}
85. 
86. 	// Use a context to determine when to stop the spinner updates.
87. 	//nolint:gosec // G118: s.cancel is stored and invoked later by Stop.
88. 	cancelCtx, cancel := context.WithCancel(ctx)
89. 	s.cancel = cancel
90. 
91. 	// Periodic update goroutine
92. 	go func(ctx context.Context) {
93. 		for {
94. 			select {
95. 			// Context is stopped, exit
