239. func (cli *CLI) heartbeat(description string, done <-chan struct{}) {
240. 	start := time.Now()
241. 	for {
242. 		select {
243. 		case <-time.After(HeartbeatInterval):
244. 			cli.T.Logf("[heartbeat] command %s is still running after %s",
245. 				description, time.Since(start).Truncate(time.Second))
246. 		case <-done:
247. 			return
248. 		}
249. 	}
250. }
