540. // installInternal installs an extension and its dependencies.
541. // skipDependencyValidation bypasses the installed-dependency constraint check; it is set by the
542. // upgrade flow so dependency reconciliation can run after the parent has been reinstalled.
543. // visited contains the ids currently in flight, which prevents dependency cycles.
544. func (m *Manager) installInternal(
545. 	ctx context.Context,
546. 	extension *ExtensionMetadata,
547. 	opts InstallOptions,
548. 	skipDependencyValidation bool,
549. 	visited map[string]struct{},
550. ) (extVersion *ExtensionVersion, err error) {
551. 	if extension == nil {
552. 		return nil, fmt.Errorf("extension metadata cannot be nil")
553. 	}
554. 
555. 	if _, inFlight := visited[extension.Id]; inFlight {
556. 		return nil, fmt.Errorf(
557. 			"dependency cycle detected involving extension %s",
558. 			extension.Id,
559. 		)
560. 	}
561. 	visited[extension.Id] = struct{}{}
562. 	defer delete(visited, extension.Id)
563. 
564. 	ctx, span := tracing.Start(ctx, events.ExtensionInstallEvent)
565. 	// Set the extension id immediately so failure spans can be correlated to the
566. 	// extension being installed. The version is added later, once it has been resolved.
567. 	span.SetAttributes(fields.ExtensionId.String(extension.Id))
568. 	defer func() {
569. 		span.EndWithStatus(err)
570. 	}()
571. 
572. 	installed, err := m.GetInstalled(FilterOptions{Id: extension.Id})
573. 	if err == nil && installed != nil {
574. 		return nil, fmt.Errorf("%s %w", extension.Id, ErrExtensionInstalled)
575. 	}
576. 
577. 	// Resolve to the latest published version that satisfies the preference.
578. 	selectedVersion, err := resolveExtensionVersion(extension, opts.VersionPreference, opts.AzdVersion)
579. 	if err != nil {
580. 		return nil, err
581. 	}
582. 
583. 	// Record the resolved version on the span so failures during install
584. 	// (artifact download, checksum, copy, config save) still emit it.
585. 	span.SetAttributes(fields.ExtensionVersion.String(selectedVersion.Version))
586. 
587. 	// Binaries are optional as long as dependencies are provided
588. 	// This allows for extensions that are just extension packs
589. 	if len(selectedVersion.Artifacts) == 0 && len(selectedVersion.Dependencies) == 0 {
590. 		return nil, fmt.Errorf("no binaries or dependencies available for this version")
591. 	}
592. 
593. 	// Install dependencies unless the caller opted out. Skipping bypasses both the
594. 	// dependency install loop and the installed-dependency constraint check, so the
595. 	// target extension installs even when the registry's dependency graph is
596. 	// transiently inconsistent (e.g. during a coordinated multi-extension bump).
597. 	if !opts.SkipDependencies && len(selectedVersion.Dependencies) > 0 {
598. 		for _, dependency := range selectedVersion.Dependencies {
599. 			installedDependency, err := m.GetInstalled(FilterOptions{Id: dependency.Id})
600. 			if err == nil && installedDependency != nil {
601. 				if !skipDependencyValidation &&
602. 					dependency.Version != "" &&
603. 					!matchesVersionConstraint(dependency.Version, installedDependency.Version) {
604. 					return nil, fmt.Errorf(
605. 						"installed dependency %s version %s does not satisfy constraint %q",
606. 						dependency.Id, installedDependency.Version, dependency.Version,
607. 					)
608. 				}
609. 				continue
610. 			}
611. 
612. 			// Find the dependency extension metadata first
613. 			dependencyOptions := &FilterOptions{
614. 				Id:      dependency.Id,
615. 				Version: dependency.Version,
616. 				Source:  extension.Source, // Use same source as parent extension
617. 			}
618. 
619. 			dependencyMatches, err := m.FindExtensions(ctx, dependencyOptions)
620. 			if err != nil {
621. 				return nil, fmt.Errorf("failed to find dependency %s: %w", dependency.Id, err)
622. 			}
623. 
624. 			if len(dependencyMatches) == 0 {
625. 				return nil, &DependencyNotFoundError{DependencyId: dependency.Id, ParentId: extension.Id}
626. 			}
627. 
628. 			if len(dependencyMatches) > 1 {
629. 				return nil, &DependencyAmbiguousSourceError{
630. 					DependencyId: dependency.Id,
631. 					ParentId:     extension.Id,
632. 					Sources:      dependencySources(dependencyMatches),
633. 				}
634. 			}
635. 
636. 			dependencyMetadata := dependencyMatches[0]
637. 
638. 			dependencyOpts := InstallOptions{
639. 				VersionPreference: dependency.Version,
640. 				AzdVersion:        opts.AzdVersion,
641. 			}
642. 			if _, err := m.installInternal(ctx, dependencyMetadata, dependencyOpts, false, visited); err != nil {
643. 				if !errors.Is(err, ErrExtensionInstalled) {
644. 					return nil, fmt.Errorf("failed to install dependency: %w", err)
645. 				}
646. 			}
647. 		}
648. 	}
649. 
650. 	hasArtifact := len(selectedVersion.Artifacts) > 0
651. 	var relativeExtensionPath string
652. 	var targetPath string
653. 
654. 	// Install the artifacts
655. 	if hasArtifact {
656. 		// Step 3: Find the artifact for the current OS
657. 		artifact, err := findArtifactForCurrentOS(selectedVersion)
658. 		if err != nil {
659. 			return nil, fmt.Errorf("failed to find artifact for current OS: %w", err)
660. 		}
661. 
662. 		// Step 4: Download the artifact to a temp location
663. 		tempFilePath, err := m.downloadArtifact(ctx, artifact.URL)
664. 		if err != nil {
665. 			return nil, fmt.Errorf("failed to download artifact: %w", err)
666. 		}
667. 
668. 		// Clean up the temp file after all scenarios
669. 		defer os.Remove(tempFilePath)
670. 
671. 		// Step 5: Validate the checksum if provided
672. 		if err := validateChecksum(tempFilePath, artifact.Checksum); err != nil {
673. 			return nil, fmt.Errorf("checksum validation failed: %w", err)
674. 		}
675. 
676. 		userConfigDir, err := config.GetUserConfigDir()
677. 		if err != nil {
678. 			return nil, fmt.Errorf("failed to get user config directory: %w", err)
679. 		}
680. 
681. 		targetDir := filepath.Join(userConfigDir, "extensions", extension.Id)
682. 		if err := os.MkdirAll(targetDir, os.ModePerm); err != nil {
683. 			return nil, fmt.Errorf("failed to create target directory: %w", err)
684. 		}
685. 
686. 		// Step 6: Copy the artifact to the target directory
687. 		// Check if artifact is a zip file, if so extract it to the target directory
688. 		if strings.HasSuffix(tempFilePath, ".zip") {
689. 			if err := rzip.ExtractToDirectory(tempFilePath, targetDir); err != nil {
690. 				return nil, fmt.Errorf("failed to extract zip file: %w", err)
691. 			}
692. 		} else if strings.HasSuffix(tempFilePath, ".tar.gz") {
693. 			if err := rzip.ExtractTarGzToDirectory(tempFilePath, targetDir); err != nil {
694. 				return nil, fmt.Errorf("failed to extract tar.gz file: %w", err)
695. 			}
696. 		} else {
697. 			targetPath = filepath.Join(targetDir, filepath.Base(tempFilePath))
698. 			if err := copyFile(tempFilePath, targetPath); err != nil {
699. 				return nil, fmt.Errorf("failed to copy artifact to target location: %w", err)
700. 			}
701. 		}
702. 
703. 		entryPoint := selectedVersion.EntryPoint
704. 		if platformEntryPoint, has := artifact.AdditionalMetadata["entryPoint"]; has {
705. 			entryPoint = fmt.Sprint(platformEntryPoint)
706. 		}
707. 		if entryPoint == "" {
708. 			switch runtime.GOOS {
709. 			case "windows":
710. 				entryPoint = fmt.Sprintf("%s.exe", extension.Id)
711. 			default:
712. 				entryPoint = extension.Id
713. 			}
714. 		}
715. 
716. 		targetPath := filepath.Join(targetDir, entryPoint)
717. 
718. 		// Prevent path traversal attacks by ensuring entryPoint stays within the extension install directory
719. 		if !osutil.IsPathContained(targetDir, targetPath) {
720. 			return nil, fmt.Errorf(
721. 				"invalid entry point path: entry point %q resolves outside extension directory. "+
722. 					"Use relative paths (e.g., 'bin/myext' or 'bin\\myext') without '..' sequences", entryPoint)
723. 		}
724. 
725. 		// Need to set the executable permission for the binary
726. 		// This change is specifically required for Linux but will apply consistently across all platforms
727. 		if err := os.Chmod(targetPath, osutil.PermissionExecutableFile); err != nil {
728. 			return nil, fmt.Errorf("failed to set executable permission: %w", err)
729. 		}
730. 
731. 		relativeExtensionPath, err = filepath.Rel(userConfigDir, targetPath)
732. 		if err != nil {
733. 			return nil, fmt.Errorf("failed to get relative path: %w", err)
734. 		}
735. 	}

